/*! Minimal jQuery-like helper for demo purposes */
(function (window, document) {
    'use strict';

    function MQ(selectorOrElements) {
        if (!(this instanceof MQ)) {
            return new MQ(selectorOrElements);
        }

        if (typeof selectorOrElements === 'string') {
            this.elements = Array.prototype.slice.call(document.querySelectorAll(selectorOrElements));
        } else if (selectorOrElements instanceof Element || selectorOrElements === window || selectorOrElements === document) {
            this.elements = [selectorOrElements];
        } else if (selectorOrElements && selectorOrElements.length) {
            this.elements = Array.prototype.slice.call(selectorOrElements);
        } else {
            this.elements = [];
        }
    }

    MQ.prototype.on = function (eventName, handler) {
        this.elements.forEach(function (element) {
            element.addEventListener(eventName, handler);
        });
        return this;
    };

    MQ.prototype.each = function (callback) {
        this.elements.forEach(function (element, index) {
            callback.call(element, index, element);
        });
        return this;
    };

    MQ.prototype.attr = function (name, value) {
        if (value === undefined) {
            return this.elements[0] ? this.elements[0].getAttribute(name) : undefined;
        }
        this.elements.forEach(function (element) {
            element.setAttribute(name, value);
        });
        return this;
    };

    MQ.prototype.toggleClass = function (className, force) {
        this.elements.forEach(function (element) {
            if (force === undefined) {
                element.classList.toggle(className);
            } else {
                element.classList.toggle(className, force);
            }
        });
        return this;
    };

    MQ.prototype.addClass = function (className) {
        this.elements.forEach(function (element) {
            element.classList.add(className);
        });
        return this;
    };

    MQ.prototype.removeClass = function (className) {
        this.elements.forEach(function (element) {
            element.classList.remove(className);
        });
        return this;
    };

    MQ.prototype.closest = function (selector) {
        if (!this.elements[0]) {
            return MQ([]);
        }
        return MQ(this.elements[0].closest(selector));
    };

    MQ.prototype.find = function (selector) {
        if (!this.elements[0]) {
            return MQ([]);
        }
        return MQ(this.elements[0].querySelectorAll(selector));
    };

    MQ.prototype.data = function (key, value) {
        if (!this.elements[0]) {
            return undefined;
        }
        if (value === undefined) {
            return this.elements[0].dataset[key];
        }
        this.elements.forEach(function (element) {
            element.dataset[key] = value;
        });
        return this;
    };

    MQ.prototype.html = function (value) {
        if (value === undefined) {
            return this.elements[0] ? this.elements[0].innerHTML : '';
        }
        this.elements.forEach(function (element) {
            element.innerHTML = value;
        });
        return this;
    };

    MQ.prototype.append = function (value) {
        this.elements.forEach(function (element) {
            element.insertAdjacentHTML('beforeend', value);
        });
        return this;
    };

    function $(selectorOrCallback) {
        if (typeof selectorOrCallback === 'function') {
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', selectorOrCallback);
            } else {
                selectorOrCallback();
            }
            return;
        }

        return MQ(selectorOrCallback);
    }

    $.getJSON = function (url, data, callback) {
        var queryString = '';
        if (data && typeof data === 'object') {
            queryString = '?' + new URLSearchParams(data).toString();
        }

        fetch(url + queryString, {
            method: 'GET',
            headers: {
                'Accept': 'application/json'
            }
        })
            .then(function (response) { return response.json(); })
            .then(function (json) { callback(json); })
            .catch(function () {
                callback({ success: false, message: 'Error de red' });
            });
    };

    window.$ = window.jQuery = $;
})(window, document);
